# C0650 · Leer/Escribir CSV (UTF-8) (Intermedio, IO)
# Perl · Text::CSV
# cpan Text::CSV
use Text::CSV;

sub solve {
  my ($in, $out) = ("input.csv","output.csv");
  my $csv = Text::CSV->new({ binary => 1, auto_diag => 1 });
  open my $fh, "<:encoding(UTF-8)", $in or die $!;
  open my $oh, ">:encoding(UTF-8)", $out or die $!;

  my $header = $csv->getline($fh);
  $csv->say($oh, $header);

  my %idx; for my $i (0..$#$header){ $idx{lc $header->[$i]} = $i }
  my $email_i = $idx{"email"};

  while (my $row = $csv->getline($fh)) {
    if (defined $email_i) { $row->[$email_i] = lc($row->[$email_i] // "") }
    $csv->say($oh, $row);
  }
  close $fh; close $oh;
}

